@file:Suppress("PackageName", "unused")
package com.MuhammadZidane.Aplicash

import android.os.Bundle
import androidx.activity.ComponentActivity
import androidx.activity.compose.setContent
import androidx.activity.enableEdgeToEdge
import androidx.compose.foundation.background
import androidx.compose.foundation.layout.*
import androidx.compose.foundation.lazy.LazyColumn
import androidx.compose.foundation.lazy.items
import androidx.compose.foundation.shape.CircleShape
import androidx.compose.foundation.shape.RoundedCornerShape
import androidx.compose.material.icons.Icons
import androidx.compose.material.icons.filled.*
import androidx.compose.material.icons.outlined.*
import androidx.compose.material3.*
import androidx.compose.runtime.*
import androidx.compose.ui.Alignment
import androidx.compose.ui.Modifier
import androidx.compose.ui.draw.clip
import androidx.compose.ui.graphics.Brush
import androidx.compose.ui.graphics.Color
import androidx.compose.ui.graphics.vector.ImageVector
import androidx.compose.ui.text.font.FontWeight
import androidx.compose.ui.tooling.preview.Preview
import androidx.compose.ui.unit.dp
import androidx.compose.ui.unit.sp
import com.MuhammadZidane.Aplicash.ui.theme.AplicashTheme

class MainActivity : ComponentActivity() {
    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)
        enableEdgeToEdge()
        setContent {
            AplicashTheme {
                HomeScreen()
            }
        }
    }
}

// Models to structure data instead of using raw hardcoded variables throughout
data class UserProfile(val name: String, val shopName: String)
data class RevenueState(val amount: Long, val trendPercentage: Int, val isActive: Boolean, val activeHours: String)
data class SummaryData(val totalOrders: Int, val bestSellingProduct: String)
data class TransactionItem(val id: String, val customerName: String, val amount: Long, val time: String, val status: TransactionStatus)
enum class TransactionStatus(val label: String, val color: Color) {
    COMPLETED("Selesai", Color(0xFFE8F5E9)),
    PENDING("Proses", Color(0xFFFFF3E0)),
    CANCELLED("Batal", Color(0xFFFFEBEE))
}

@Composable
fun HomeScreen(
    // Using default empty/zero states to avoid heavy dummy data dependency
    userProfile: UserProfile = UserProfile("Nama Pengguna", "Nama Toko"),
    revenueState: RevenueState = RevenueState(0L, 0, false, "00:00 - 00:00"),
    summaryData: SummaryData = SummaryData(0, "-"),
    transactions: List<TransactionItem> = emptyList()
) {
    var searchQuery by remember { mutableStateOf("") }

    Scaffold(
        bottomBar = { AppBottomNavigation() },
        containerColor = Color(0xFFF8F9FA)
    ) { innerPadding ->
        LazyColumn(
            modifier = Modifier
                .fillMaxSize()
                .padding(innerPadding)
                .padding(horizontal = 20.dp),
            contentPadding = PaddingValues(vertical = 24.dp),
            verticalArrangement = Arrangement.spacedBy(24.dp)
        ) {
            item { TopHeader(userProfile) }
            item { SearchSection(searchQuery, onQueryChange = { searchQuery = it }) }
            item { RevenueBanner(revenueState) }
            item { ActionGrid() }
            item { SummarySection(summaryData) }
            item { RecentTransactionsHeader() }
            if (transactions.isEmpty()) {
                item {
                    Text(
                        text = "Belum ada transaksi",
                        color = Color.Gray,
                        modifier = Modifier.padding(vertical = 16.dp)
                    )
                }
            } else {
                items(transactions) { tx -> TransactionRow(tx) }
            }
        }
    }
}

@Composable
fun TopHeader(userProfile: UserProfile) {
    Row(
        modifier = Modifier.fillMaxWidth(),
        horizontalArrangement = Arrangement.SpaceBetween,
        verticalAlignment = Alignment.CenterVertically
    ) {
        Row(verticalAlignment = Alignment.CenterVertically, horizontalArrangement = Arrangement.spacedBy(12.dp)) {
            Box(
                modifier = Modifier
                    .size(48.dp)
                    .clip(CircleShape)
                    .background(Color.LightGray)
            )
            Column {
                Text(
                    text = "Halo, ${userProfile.name} ",
                    fontSize = 16.sp,
                    fontWeight = FontWeight.Medium
                )
                Text(
                    text = userProfile.shopName,
                    fontSize = 14.sp,
                    color = Color.Gray
                )
            }
        }
        IconButton(
            onClick = { /* TODO */ },
            modifier = Modifier
                .background(Color.White, CircleShape)
                .size(40.dp)
        ) {
            Icon(Icons.Outlined.Notifications, contentDescription = "Notifikasi", tint = Color(0xFF3F51B5))
        }
    }
}

@OptIn(ExperimentalMaterial3Api::class)
@Composable
fun SearchSection(query: String, onQueryChange: (String) -> Unit) {
    OutlinedTextField(
        value = query,
        onValueChange = onQueryChange,
        modifier = Modifier.fillMaxWidth(),
        placeholder = { Text("Cari transaksi...") },
        leadingIcon = { Icon(Icons.Default.Search, contentDescription = null, tint = Color.Gray) },
        shape = RoundedCornerShape(24.dp),
        colors = OutlinedTextFieldDefaults.colors(
            unfocusedBorderColor = Color.Transparent,
            focusedBorderColor = Color.Transparent,
            unfocusedContainerColor = Color.White,
            focusedContainerColor = Color.White
        ),
        singleLine = true
    )
}

@Composable
fun RevenueBanner(state: RevenueState) {
    val gradient = Brush.linearGradient(
        colors = listOf(Color(0xFF3F51B5), Color(0xFF00BCD4))
    )
    Box(
        modifier = Modifier
            .fillMaxWidth()
            .clip(RoundedCornerShape(24.dp))
            .background(gradient)
            .padding(24.dp)
    ) {
        Column(verticalArrangement = Arrangement.spacedBy(16.dp)) {
            Row(
                modifier = Modifier.fillMaxWidth(),
                horizontalArrangement = Arrangement.SpaceBetween,
                verticalAlignment = Alignment.CenterVertically
            ) {
                Surface(
                    color = Color.White.copy(alpha = 0.2f),
                    shape = RoundedCornerShape(16.dp)
                ) {
                    Row(
                        modifier = Modifier.padding(horizontal = 12.dp, vertical = 6.dp),
                        verticalAlignment = Alignment.CenterVertically,
                        horizontalArrangement = Arrangement.spacedBy(6.dp)
                    ) {
                        Box(modifier = Modifier.size(8.dp).clip(CircleShape).background(if (state.isActive) Color.Green else Color.Red))
                        Text("POS ${if(state.isActive) "Active" else "Inactive"}", color = Color.White, fontSize = 12.sp)
                    }
                }
                Text(state.activeHours, color = Color.White, fontSize = 14.sp)
            }

            Column {
                Text("Pendapatan Hari Ini", color = Color.White.copy(alpha = 0.8f), fontSize = 14.sp)
                Spacer(modifier = Modifier.height(4.dp))
                Row(
                    modifier = Modifier.fillMaxWidth(),
                    horizontalArrangement = Arrangement.SpaceBetween,
                    verticalAlignment = Alignment.Bottom
                ) {
                    Text(
                        "Rp ${"%,d".format(state.amount).replace(',', '.')}",
                        color = Color.White,
                        fontSize = 24.sp,
                        fontWeight = FontWeight.Bold
                    )
                    Surface(
                        color = Color.White.copy(alpha = 0.2f),
                        shape = RoundedCornerShape(8.dp)
                    ) {
                        Text(
                            "+${state.trendPercentage}%",
                            color = Color.White,
                            fontSize = 12.sp,
                            modifier = Modifier.padding(horizontal = 8.dp, vertical = 4.dp)
                        )
                    }
                }
            }
        }
    }
}

@Composable
fun ActionGrid() {
    Row(
        modifier = Modifier.fillMaxWidth(),
        horizontalArrangement = Arrangement.spacedBy(16.dp)
    ) {
        // Main Action
        Surface(
            modifier = Modifier.weight(1f).height(180.dp),
            shape = RoundedCornerShape(24.dp),
            color = Color(0xFF3F51B5)
        ) {
            Column(
                modifier = Modifier.padding(20.dp),
                verticalArrangement = Arrangement.Center,
                horizontalAlignment = Alignment.CenterHorizontally
            ) {
                Icon(Icons.Default.ShoppingCart, contentDescription = null, tint = Color.White, modifier = Modifier.size(32.dp))
                Spacer(modifier = Modifier.height(16.dp))
                Text("Transaksi", color = Color.White, fontWeight = FontWeight.Bold, fontSize = 16.sp)
                Text("Buat pesanan baru", color = Color.White.copy(alpha = 0.8f), fontSize = 12.sp, modifier = Modifier.padding(top = 4.dp))
            }
        }

        // Secondary Actions
        Column(
            modifier = Modifier.weight(1f).height(180.dp),
            verticalArrangement = Arrangement.spacedBy(16.dp)
        ) {
            Surface(
                modifier = Modifier.weight(1f).fillMaxWidth(),
                shape = RoundedCornerShape(20.dp),
                color = Color(0xFFFFF0F5)
            ) {
                @Suppress("DEPRECATION")
                Row(
                    modifier = Modifier.padding(16.dp),
                    horizontalArrangement = Arrangement.SpaceBetween,
                    verticalAlignment = Alignment.CenterVertically
                ) {
                    Column {
                        Text("Laporan", fontWeight = FontWeight.Bold, color = Color(0xFFE91E63))
                        Text("Lihat detail", fontSize = 12.sp, color = Color(0xFFE91E63).copy(alpha = 0.8f))
                    }
                    Icon(Icons.Default.List, contentDescription = null, tint = Color(0xFFE91E63))
                }
            }
            Row(modifier = Modifier.weight(1f), horizontalArrangement = Arrangement.spacedBy(16.dp)) {
                ActionMiniCard(modifier = Modifier.weight(1f), title = "Produk", icon = Icons.Default.ShoppingCart, bgColor = Color(0xFFE0F7FA), tint = Color(0xFF00BCD4))
                ActionMiniCard(modifier = Modifier.weight(1f), title = "Printer", icon = Icons.Default.Build, bgColor = Color(0xFFEEEEEE), tint = Color(0xFF616161))
            }
        }
    }
}

@Composable
fun ActionMiniCard(modifier: Modifier = Modifier, title: String, icon: ImageVector, bgColor: Color, tint: Color) {
    Surface(
        modifier = modifier.fillMaxHeight(),
        shape = RoundedCornerShape(20.dp),
        color = bgColor
    ) {
        Column(
            modifier = Modifier.padding(12.dp),
            verticalArrangement = Arrangement.Center,
            horizontalAlignment = Alignment.CenterHorizontally
        ) {
            Icon(icon, contentDescription = title, tint = tint)
            Spacer(modifier = Modifier.height(8.dp))
            Text(title, fontSize = 12.sp, color = tint.copy(alpha = 0.8f), fontWeight = FontWeight.Medium)
        }
    }
}

@Composable
fun SummarySection(data: SummaryData) {
    Text("Ringkasan", fontWeight = FontWeight.Bold, fontSize = 18.sp)
    Spacer(modifier = Modifier.height(12.dp))
    Row(horizontalArrangement = Arrangement.spacedBy(16.dp)) {
        SummaryCard(modifier = Modifier.weight(1f), title = "Total Order", value = data.totalOrders.toString(), progress = 0.7f)
        SummaryCard(modifier = Modifier.weight(1f), title = "Produk Terlaris", value = data.bestSellingProduct, progress = 0.9f)
    }
}

@Composable
fun SummaryCard(modifier: Modifier = Modifier, title: String, value: String, progress: Float) {
    Surface(
        modifier = modifier,
        shape = RoundedCornerShape(20.dp),
        color = Color.White
    ) {
        Column(modifier = Modifier.padding(16.dp)) {
            Text(title, color = Color.Gray, fontSize = 14.sp)
            Spacer(modifier = Modifier.height(12.dp))
            Text(value, fontWeight = FontWeight.Bold, fontSize = 16.sp)
            Spacer(modifier = Modifier.height(12.dp))
            LinearProgressIndicator(
                progress = { progress },
                modifier = Modifier.fillMaxWidth().height(6.dp).clip(RoundedCornerShape(3.dp)),
                color = Color(0xFF3F51B5),
                trackColor = Color(0xFFEEEEEE)
            )
        }
    }
}

@Composable
fun RecentTransactionsHeader() {
    Row(
        modifier = Modifier.fillMaxWidth(),
        horizontalArrangement = Arrangement.SpaceBetween,
        verticalAlignment = Alignment.CenterVertically
    ) {
        Text("Transaksi Terakhir", fontWeight = FontWeight.Bold, fontSize = 18.sp)
        TextButton(onClick = { /* TODO */ }) {
            Text("Lihat Semua", color = Color(0xFF3F51B5))
        }
    }
}

@Composable
fun TransactionRow(tx: TransactionItem) {
    Surface(
        color = Color.White,
        shape = RoundedCornerShape(16.dp)
    ) {
        Row(
            modifier = Modifier.fillMaxWidth().padding(16.dp),
            verticalAlignment = Alignment.CenterVertically,
            horizontalArrangement = Arrangement.spacedBy(16.dp)
        ) {
            Box(
                modifier = Modifier.size(48.dp).clip(CircleShape).background(Color(0xFFE8EAF6)),
                contentAlignment = Alignment.Center
            ) {
                Text(tx.customerName.take(1).uppercase(), color = Color(0xFF3F51B5), fontWeight = FontWeight.Bold)
            }
            Column(modifier = Modifier.weight(1f)) {
                Text(tx.customerName, fontWeight = FontWeight.Medium, fontSize = 16.sp)
                Text("${tx.id} • ${tx.time}", color = Color.Gray, fontSize = 12.sp)
            }
            Column(horizontalAlignment = Alignment.End) {
                Text("Rp ${"%,d".format(tx.amount).replace(',', '.')}", fontWeight = FontWeight.Bold)
                Surface(
                    color = tx.status.color,
                    shape = RoundedCornerShape(8.dp),
                    modifier = Modifier.padding(top = 4.dp)
                ) {
                    Text(
                        tx.status.label,
                        color = Color.DarkGray,
                        fontSize = 12.sp,
                        modifier = Modifier.padding(horizontal = 8.dp, vertical = 2.dp)
                    )
                }
            }
        }
    }
}

@Composable
fun AppBottomNavigation() {
    NavigationBar(
        containerColor = Color.White,
        tonalElevation = 8.dp
    ) {
        NavigationBarItem(
            selected = true,
            onClick = { },
            icon = { Icon(Icons.Default.Home, contentDescription = "Beranda") },
            label = { Text("Beranda") },
            colors = NavigationBarItemDefaults.colors(selectedIconColor = Color(0xFF3F51B5), selectedTextColor = Color(0xFF3F51B5))
        )
        NavigationBarItem(
            selected = false,
            onClick = { },
            icon = { Icon(Icons.Default.ShoppingCart, contentDescription = "Transaksi") },
            label = { Text("Transaksi") }
        )
        Box(
            modifier = Modifier
                .padding(8.dp)
                .size(56.dp)
                .clip(CircleShape)
                .background(Color(0xFF3F51B5)),
            contentAlignment = Alignment.Center
        ) {
            Icon(Icons.Default.Search, contentDescription = "Scan", tint = Color.White)
        }
        NavigationBarItem(
            selected = false,
            onClick = { },
            icon = { Icon(Icons.Default.Info, contentDescription = "Laporan") },
            label = { Text("Laporan") }
        )
        NavigationBarItem(
            selected = false,
            onClick = { },
            icon = { Icon(Icons.Default.Menu, contentDescription = "Menu") },
            label = { Text("Menu") }
        )
    }
}

@Preview(showBackground = true)
@Composable
fun HomeScreenPreview() {
    AplicashTheme {
        HomeScreen(
            userProfile = UserProfile("Juragan", "Toko Kelontong Berkah"),
            revenueState = RevenueState(2450000L, 12, true, "08:00 - 22:00"),
            summaryData = SummaryData(128, "Kopi Susu Gula Aren"),
            transactions = listOf(
                TransactionItem("ORD-001", "Budi Santoso", 45000, "10:45", TransactionStatus.COMPLETED),
                TransactionItem("ORD-002", "Siti Aminah", 120000, "10:30", TransactionStatus.COMPLETED)
            )
        )
    }
}

@file:Suppress("PackageName", "unused")
package com.MuhammadZidane.Aplicash

import android.os.Bundle
import androidx.activity.ComponentActivity
import androidx.activity.compose.setContent
import androidx.activity.enableEdgeToEdge
import androidx.compose.foundation.background
import androidx.compose.foundation.layout.*
import androidx.compose.foundation.lazy.LazyColumn
import androidx.compose.foundation.lazy.items
import androidx.compose.foundation.shape.CircleShape
import androidx.compose.foundation.shape.RoundedCornerShape
import androidx.compose.material.icons.Icons
import androidx.compose.material.icons.filled.*
import androidx.compose.material.icons.outlined.*
import androidx.compose.material3.*
import androidx.compose.runtime.*
import androidx.compose.ui.Alignment
import androidx.compose.ui.Modifier
import androidx.compose.ui.draw.clip
import androidx.compose.ui.graphics.Brush
import androidx.compose.ui.graphics.Color
import androidx.compose.ui.graphics.vector.ImageVector
import androidx.compose.ui.text.font.FontWeight
import androidx.compose.ui.tooling.preview.Preview
import androidx.compose.ui.unit.dp
import androidx.compose.ui.unit.sp
import com.MuhammadZidane.Aplicash.ui.theme.AplicashTheme

class MainActivity : ComponentActivity() {
    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)
        enableEdgeToEdge()
        setContent {
            AplicashTheme {
                HomeScreen()
            }
        }
    }
}

// Models to structure data instead of using raw hardcoded variables throughout
data class UserProfile(val name: String, val shopName: String)
data class RevenueState(val amount: Long, val trendPercentage: Int, val isActive: Boolean, val activeHours: String)
data class SummaryData(val totalOrders: Int, val bestSellingProduct: String)
data class TransactionItem(val id: String, val customerName: String, val amount: Long, val time: String, val status: TransactionStatus)

// Modern color palette for status
enum class TransactionStatus(val label: String, val color: Color, val textColor: Color) {
    COMPLETED("Selesai", Color(0xFFDCFCE7), Color(0xFF166534)),
    PENDING("Proses", Color(0xFFFEF3C7), Color(0xFF9A3412)),
    CANCELLED("Batal", Color(0xFFFEE2E2), Color(0xFF991B1B))
}

// Brand Colors
private val BrandPrimary = Color(0xFF4F46E5)
private val BrandGradientStart = Color(0xFF6366F1)
private val BrandGradientEnd = Color(0xFF4338CA)
private val BgGray = Color(0xFFF8FAFC)
private val TextDark = Color(0xFF0F172A)
private val TextGray = Color(0xFF64748B)

@Composable
fun HomeScreen(
    // Using default empty/zero states to avoid heavy dummy data dependency
    userProfile: UserProfile = UserProfile("Nama Pengguna", "Nama Toko"),
    revenueState: RevenueState = RevenueState(0L, 0, false, "00:00 - 00:00"),
    summaryData: SummaryData = SummaryData(0, "-"),
    transactions: List<TransactionItem> = emptyList()
) {
    var searchQuery by remember { mutableStateOf("") }

    Scaffold(
        bottomBar = { AppBottomNavigation() },
        containerColor = BgGray
    ) { innerPadding ->
        LazyColumn(
            modifier = Modifier
                .fillMaxSize()
                .padding(innerPadding)
                .padding(horizontal = 20.dp),
            contentPadding = PaddingValues(vertical = 24.dp),
            verticalArrangement = Arrangement.spacedBy(24.dp)
        ) {
            item { TopHeader(userProfile) }
            item { SearchSection(searchQuery, onQueryChange = { searchQuery = it }) }
            item { RevenueBanner(revenueState) }
            item { ActionGrid() }
            item { SummarySection(summaryData) }
            item { RecentTransactionsHeader() }
            if (transactions.isEmpty()) {
                item {
                    Text(
                        text = "Belum ada transaksi",
                        color = TextGray,
                        modifier = Modifier.padding(vertical = 16.dp)
                    )
                }
            } else {
                items(transactions) { tx -> TransactionRow(tx) }
            }
        }
    }
}

@Composable
fun TopHeader(userProfile: UserProfile) {
    Row(
        modifier = Modifier.fillMaxWidth(),
        horizontalArrangement = Arrangement.SpaceBetween,
        verticalAlignment = Alignment.CenterVertically
    ) {
        Row(verticalAlignment = Alignment.CenterVertically, horizontalArrangement = Arrangement.spacedBy(12.dp)) {
            Box(
                modifier = Modifier
                    .size(48.dp)
                    .clip(CircleShape)
                    .background(Color(0xFFE2E8F0))
            )
            Column {
                Text(
                    text = "Halo, ${userProfile.name} ",
                    fontSize = 16.sp,
                    fontWeight = FontWeight.SemiBold,
                    color = TextDark
                )
                Text(
                    text = userProfile.shopName,
                    fontSize = 14.sp,
                    color = TextGray
                )
            }
        }
        IconButton(
            onClick = { /* TODO */ },
            modifier = Modifier
                .background(Color.White, CircleShape)
                .size(40.dp)
        ) {
            Icon(Icons.Outlined.Notifications, contentDescription = "Notifikasi", tint = TextDark)
        }
    }
}

@OptIn(ExperimentalMaterial3Api::class)
@Composable
fun SearchSection(query: String, onQueryChange: (String) -> Unit) {
    OutlinedTextField(
        value = query,
        onValueChange = onQueryChange,
        modifier = Modifier.fillMaxWidth(),
        placeholder = { Text("Cari transaksi...", color = Color(0xFF94A3B8)) },
        leadingIcon = { Icon(Icons.Default.Search, contentDescription = null, tint = Color(0xFF94A3B8)) },
        shape = RoundedCornerShape(24.dp),
        colors = OutlinedTextFieldDefaults.colors(
            unfocusedBorderColor = Color.Transparent,
            focusedBorderColor = Color.Transparent,
            unfocusedContainerColor = Color.White,
            focusedContainerColor = Color.White
        ),
        singleLine = true
    )
}

@Composable
fun RevenueBanner(state: RevenueState) {
    val gradient = Brush.linearGradient(
        colors = listOf(BrandGradientStart, BrandGradientEnd)
    )
    Box(
        modifier = Modifier
            .fillMaxWidth()
            .clip(RoundedCornerShape(24.dp))
            .background(gradient)
            .padding(24.dp)
    ) {
        Column(verticalArrangement = Arrangement.spacedBy(16.dp)) {
            Row(
                modifier = Modifier.fillMaxWidth(),
                horizontalArrangement = Arrangement.SpaceBetween,
                verticalAlignment = Alignment.CenterVertically
            ) {
                Surface(
                    color = Color.White.copy(alpha = 0.2f),
                    shape = RoundedCornerShape(16.dp)
                ) {
                    Row(
                        modifier = Modifier.padding(horizontal = 12.dp, vertical = 6.dp),
                        verticalAlignment = Alignment.CenterVertically,
                        horizontalArrangement = Arrangement.spacedBy(6.dp)
                    ) {
                        Box(modifier = Modifier.size(8.dp).clip(CircleShape).background(if (state.isActive) Color(0xFF4ADE80) else Color(0xFFF87171)))
                        Text("POS ${if(state.isActive) "Active" else "Inactive"}", color = Color.White, fontSize = 12.sp, fontWeight = FontWeight.Medium)
                    }
                }
                Text(state.activeHours, color = Color.White, fontSize = 14.sp, fontWeight = FontWeight.Medium)
            }

            Column {
                Text("Pendapatan Hari Ini", color = Color.White.copy(alpha = 0.9f), fontSize = 14.sp)
                Spacer(modifier = Modifier.height(4.dp))
                Row(
                    modifier = Modifier.fillMaxWidth(),
                    horizontalArrangement = Arrangement.SpaceBetween,
                    verticalAlignment = Alignment.Bottom
                ) {
                    Text(
                        "Rp ${"%,d".format(state.amount).replace(',', '.')}",
                        color = Color.White,
                        fontSize = 24.sp,
                        fontWeight = FontWeight.Bold
                    )
                    Surface(
                        color = Color.White.copy(alpha = 0.2f),
                        shape = RoundedCornerShape(8.dp)
                    ) {
                        Text(
                            "+${state.trendPercentage}%",
                            color = Color.White,
                            fontSize = 12.sp,
                            fontWeight = FontWeight.SemiBold,
                            modifier = Modifier.padding(horizontal = 8.dp, vertical = 4.dp)
                        )
                    }
                }
            }
        }
    }
}

@Composable
fun ActionGrid() {
    Row(
        modifier = Modifier.fillMaxWidth(),
        horizontalArrangement = Arrangement.spacedBy(16.dp)
    ) {
        // Main Action
        Surface(
            modifier = Modifier.weight(1f).height(180.dp),
            shape = RoundedCornerShape(24.dp),
            color = Color(0xFF1E293B) // Elegan dark slate daripada warna warni mencolok
        ) {
            Column(
                modifier = Modifier.padding(20.dp),
                verticalArrangement = Arrangement.Center,
                horizontalAlignment = Alignment.CenterHorizontally
            ) {
                Icon(Icons.Default.ShoppingCart, contentDescription = null, tint = Color.White, modifier = Modifier.size(32.dp))
                Spacer(modifier = Modifier.height(16.dp))
                Text("Transaksi", color = Color.White, fontWeight = FontWeight.SemiBold, fontSize = 16.sp)
                Text("Buat pesanan baru", color = Color.White.copy(alpha = 0.7f), fontSize = 12.sp, modifier = Modifier.padding(top = 4.dp))
            }
        }

        // Secondary Actions
        Column(
            modifier = Modifier.weight(1f).height(180.dp),
            verticalArrangement = Arrangement.spacedBy(16.dp)
        ) {
            Surface(
                modifier = Modifier.weight(1f).fillMaxWidth(),
                shape = RoundedCornerShape(20.dp),
                color = Color.White // Clean white background yang lebih nyatu dan natural
            ) {
                @Suppress("DEPRECATION")
                Row(
                    modifier = Modifier.padding(16.dp),
                    horizontalArrangement = Arrangement.SpaceBetween,
                    verticalAlignment = Alignment.CenterVertically
                ) {
                    Column {
                        Text("Laporan", fontWeight = FontWeight.SemiBold, color = TextDark)
                        Text("Lihat detail", fontSize = 12.sp, color = TextGray)
                    }
                    Icon(Icons.Default.List, contentDescription = null, tint = BrandPrimary)
                }
            }
            Row(modifier = Modifier.weight(1f), horizontalArrangement = Arrangement.spacedBy(16.dp)) {
                ActionMiniCard(modifier = Modifier.weight(1f), title = "Produk", icon = Icons.Default.ShoppingCart, bgColor = Color.White, tint = TextDark)
                ActionMiniCard(modifier = Modifier.weight(1f), title = "Printer", icon = Icons.Default.Build, bgColor = Color.White, tint = TextDark)
            }
        }
    }
}

@Composable
fun ActionMiniCard(modifier: Modifier = Modifier, title: String, icon: ImageVector, bgColor: Color, tint: Color) {
    Surface(
        modifier = modifier.fillMaxHeight(),
        shape = RoundedCornerShape(20.dp),
        color = bgColor
    ) {
        Column(
            modifier = Modifier.padding(12.dp),
            verticalArrangement = Arrangement.Center,
            horizontalAlignment = Alignment.CenterHorizontally
        ) {
            Icon(icon, contentDescription = title, tint = tint)
            Spacer(modifier = Modifier.height(8.dp))
            Text(title, fontSize = 12.sp, color = TextDark, fontWeight = FontWeight.Medium)
        }
    }
}

@Composable
fun SummarySection(data: SummaryData) {
    Text("Ringkasan", fontWeight = FontWeight.SemiBold, fontSize = 18.sp, color = TextDark)
    Spacer(modifier = Modifier.height(12.dp))
    Row(horizontalArrangement = Arrangement.spacedBy(16.dp)) {
        SummaryCard(modifier = Modifier.weight(1f), title = "Total Order", value = data.totalOrders.toString(), progress = 0.7f)
        SummaryCard(modifier = Modifier.weight(1f), title = "Produk Terlaris", value = data.bestSellingProduct, progress = 0.9f)
    }
}

@Composable
fun SummaryCard(modifier: Modifier = Modifier, title: String, value: String, progress: Float) {
    Surface(
        modifier = modifier,
        shape = RoundedCornerShape(20.dp),
        color = Color.White
    ) {
        Column(modifier = Modifier.padding(16.dp)) {
            Text(title, color = TextGray, fontSize = 14.sp)
            Spacer(modifier = Modifier.height(12.dp))
            Text(value, fontWeight = FontWeight.SemiBold, fontSize = 16.sp, color = TextDark)
            Spacer(modifier = Modifier.height(12.dp))
            LinearProgressIndicator(
                progress = { progress },
                modifier = Modifier.fillMaxWidth().height(6.dp).clip(RoundedCornerShape(3.dp)),
                color = BrandPrimary,
                trackColor = Color(0xFFF1F5F9)
            )
        }
    }
}

