@Composable
fun TransactionRow(tx: TransactionItem) {
    Surface(
        color = Color.White,
        shape = RoundedCornerShape(16.dp)
    ) {
        Row(
            modifier = Modifier.fillMaxWidth().padding(16.dp),
            verticalAlignment = Alignment.CenterVertically,
            horizontalArrangement = Arrangement.spacedBy(16.dp)
        ) {
            Box(
                modifier = Modifier.size(48.dp).clip(CircleShape).background(Color(0xFFEEF2FF)),
                contentAlignment = Alignment.Center
            ) {
                Text(tx.customerName.take(1).uppercase(), color = BrandPrimary, fontWeight = FontWeight.Bold)
            }
            Column(modifier = Modifier.weight(1f)) {
                Text(tx.customerName, fontWeight = FontWeight.Medium, fontSize = 16.sp, color = TextDark)
                Text("${tx.id} • ${tx.time}", color = TextGray, fontSize = 12.sp)
            }
            Column(horizontalAlignment = Alignment.End) {
                Text("Rp ${"%,d".format(tx.amount).replace(',', '.')}", fontWeight = FontWeight.SemiBold, color = TextDark)
                Surface(
                    color = tx.status.color,
                    shape = RoundedCornerShape(8.dp),
                    modifier = Modifier.padding(top = 4.dp)
                ) {
                    Text(
                        tx.status.label,
                        color = tx.status.textColor,
                        fontSize = 12.sp,
                        fontWeight = FontWeight.Medium,
                        modifier = Modifier.padding(horizontal = 8.dp, vertical = 4.dp)
                    )
                }
            }
        }
    }
}

